usage.basic:
const items: ISelectItem[] = [
  { label: 'Option 1', code: 'opt1' },
  { label: 'Option 2', code: 'opt2' },
  { label: 'Option 3', code: 'opt3' }
];

const [selected, setSelected] = useState('opt1');

<Select
  items={items}
  selectedItem={selected}
  onChange={(item) => setSelected(item.code)}
/>

advanced.code:
const [selected, setSelected] = useState('opt1');

<Select
  items={items}
  selectedItem={selected}
  onChange={(item) => setSelected(item.code)}
  searchable={true}
  placeholder="Search options..."
  selectedBackground="linear-gradient(90deg, #667eea 0%, #764ba2 100%)"
  selectedColor="#ffffff"
  emptyItemsMessage="No results found"
/>

const handleUpdate = (item) => {
  console.log('Update item:', item);
  // Open edit modal
};

const handleDelete = (item) => {
  console.log('Delete item:', item);
  // Confirm and delete
};

<Select
  items={items}
  selectedItem={selected}
  onChange={(item) => setSelected(item.code)}
  editable={true}
  onUpdate={handleUpdate}
  onDelete={handleDelete}
/>

interface CustomItem extends ISelectItem {
  icon?: string;
  disabled?: boolean;
}

const customItems: CustomItem[] = [
  { label: 'Home', code: 'home', icon: '🏠' },
  { label: 'Settings', code: 'settings', icon: '⚙️' },
  { label: 'Profile', code: 'profile', icon: '👤', disabled: true }
];

<Select
  items={customItems}
  selectedItem={selected}
  onChange={(item) => setSelected(item.code)}
/>
